    18→
    19→/// A controller class that manages [Team] search for super_admin and super_reader.
    20→///
    21→/// This controller refreshes itself when
    22→/// - [repositoryProvider] updated.
    23→/// - [loginStateControllerProvider] updated.
    24→/// - [teamSearchFilterParametersNotifierProvider] updated.
    25→///
    26→/// Note: This controller just handles abstract repository.
    27→/// This means that the controller does not care
    28→/// the implementation of its repository is either remote DB or local cache.
    29→/// Therefore do not use anything related to a specific implementation of repository
    30→/// (e.g., the login state of the remote DB).
    31→@Riverpod(keepAlive: true)
    32→class SuperAdminTeamSearchController extends _$SuperAdminTeamSearchController
    33→    with PagePagingNotifierMixin<Team> {
    34→  static const int pageSize = 20;
    35→
    36→  @override
    37→  Future<PagingData<Team>> build() {
    38→    ref.watch(loginStateControllerProvider);
    39→    ref.watch(repositoryProvider);
    40→    final filterParams = ref.watch(teamSearchFilterParametersNotifierProvider);
    41→    return fetch(
    42→      page: PagePagingNotifierMixin.initialPage,
    43→      pageSize: pageSize,
    44→      filterParams: filterParams,
    45→    );
    46→  }
    47→
    48→  @override
    49→  Future<PagingData<Team>> fetch({
    50→    required int page,
    51→    required int pageSize,
    52→    TeamSearchFilterParameters? filterParams,
    53→  }) async {
    54→    final TeamSearchFilterParameters params =
    55→        filterParams ?? ref.read(teamSearchFilterParametersNotifierProvider);
    56→
    57→    final res = await ref.read(repositoryProvider).searchTeams(
    58→          keyword: params.keyword,
    59→          page: page,
    60→          pageSize: pageSize,
    61→          orderBy: params.orderBy,
    62→          isOrderDesc: params.isOrderDesc,
    63→          // Super Admin フィルタ
    64→          isPlanPaid: params.isPlanPaid,
    65→          isTeamPlanActive: params.isTeamPlanActive,
    66→          teamTypes: params.teamTypes,
    67→          ownerEmail: params.ownerEmail,
    68→          // 日付フィルタは将来実装
    69→          teamPlanStartDateFrom: params.teamPlanStartDateFrom,
    70→          teamPlanStartDateTo: params.teamPlanStartDateTo,
    71→          teamPlanEndDateFrom: params.teamPlanEndDateFrom,
    72→          teamPlanEndDateTo: params.teamPlanEndDateTo,
    73→          extendToNextTeamPlan: params.extendToNextTeamPlan,
    74→          isDeletionScheduled: params.isDeletionScheduled,
    75→        );
    76→
    77→    checkResultForMaintenance(ref, res);
    78→    if (!res.hasRight) {
    79→      throw res.left;
    80→    }
    81→
    82→    return PagingData<Team>(
    83→      items: res.right.teams,
    84→      page: page,
    85→      pageSize: pageSize,
    86→      total: res.right.total,
    87→      hasMore: res.right.teams.length + page * pageSize < res.right.total,
    88→    );
    89→  }
    90→}
    91→
    92→/// Filtering parameters for SuperAdminTeamSearchController.
    93→///
    94→/// This class is the state of TeamSearchFilterParametersNotifier.
    95→/// The state of StateNotifier should be immutable.
    96→@immutable
    97→class TeamSearchFilterParameters {
    98→  // 基本フィルタ
    99→  final String? keyword;
   100→  final TeamSearchRequestOrderBy orderBy;
   101→  final bool? isOrderDesc;
   102→
   103→  // Super Admin フィルタ
   104→  final bool? isPlanPaid;
   105→  final bool? isTeamPlanActive;
   106→  final List<TeamType>? teamTypes;
   107→  final String? ownerEmail;
   108→  final DateTime? teamPlanStartDateFrom;
   109→  final DateTime? teamPlanStartDateTo;
   110→  final DateTime? teamPlanEndDateFrom;
   111→  final DateTime? teamPlanEndDateTo;
   112→  final bool? extendToNextTeamPlan;
   113→  final bool? isDeletionScheduled;
   114→
   115→  const TeamSearchFilterParameters({
   116→    this.keyword,
   117→    this.orderBy = TeamSearchRequestOrderBy.name,
   118→    this.isOrderDesc,
   119→    this.isPlanPaid,
   120→    this.isTeamPlanActive,
   121→    this.teamTypes,
   122→    this.ownerEmail,
   123→    this.teamPlanStartDateFrom,
   124→    this.teamPlanStartDateTo,
   125→    this.teamPlanEndDateFrom,
   126→    this.teamPlanEndDateTo,
   127→    this.extendToNextTeamPlan,
   128→    this.isDeletionScheduled,
   129→  });
   130→
   131→  TeamSearchFilterParameters copyWith({
   132→    String? keyword,
   133→    TeamSearchRequestOrderBy? orderBy,
   134→    bool? isOrderDesc,
   135→    bool? isPlanPaid,
   136→    bool? isTeamPlanActive,
   137→    List<TeamType>? teamTypes,
   138→    String? ownerEmail,
   139→    DateTime? teamPlanStartDateFrom,
   140→    DateTime? teamPlanStartDateTo,
   141→    DateTime? teamPlanEndDateFrom,
