    36→    @Default(null) DateTime? updatedAt, // assumes UTC
    37→    @Default(null) DateTime? teamPlanCancelAt,
    38→    @Default(null) DateTime? teamPlanDowngradeAt,
    39→    @Default(null) String? imageUrl,
    40→    @Default(null) TeamPlan? teamPlan,
    41→    @Default(null) TeamPlan? nextTeamPlan,
    42→    @Default(null) String? presignedImageUrl,
    43→    @Default(null) String? billingFailureReason,
    44→    @Default(null) String? downgradePlanId,
    45→    @Default(null) Item? item,
