    47→
    48→  factory Team.fromJson(Map<String, dynamic> json) => _$TeamFromJson(json);
    49→
    50→  bool get isSingleUserTeam => teamType == TeamType.single;
    51→
    52→  /// ボール解析の使用量（TeamPlan + Item の合算）
    53→  int get ballUsage {
    54→    // プランの上限
    55→    final planMax =
    56→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.plan?.maxBalls ?? 0 : 0;
    57→
    58→    // プランの使用量
    59→    final rawPlanUsage =
    60→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.currentUsage ?? 0 : 0;
    61→
    62→    // 上限を越えないようにする
    63→    // DB 上で maxBalls == 300 にも関わらず、currentUsage == 10000 などが入った場合
    64→    // currentUsage = 300 にクランプ
    65→    final planUsage = min(rawPlanUsage, planMax);
    66→
    67→    final itemMax = item?.ballAvailableCount ?? 0;
    68→    final itemUsage = min(item?.ballUsage ?? 0, itemMax);
    69→
    70→    return planUsage + itemUsage;
    71→  }
    72→
    73→  /// AI コーチの使用量（TeamPlan + Item の合算）
    74→  int get aiCoachUsage {
    75→    final planMax = (teamPlan?.withinPeriod ?? false)
    76→        ? teamPlan?.plan?.maxAiCoachs ?? 0
    77→        : 0;
    78→
    79→    final rawPlanUsage = (teamPlan?.withinPeriod ?? false)
    80→        ? teamPlan?.currentAiCoachUsage ?? 0
    81→        : 0;
    82→
    83→    final planUsage = min(rawPlanUsage, planMax);
    84→
    85→    final itemMax = item?.aiCoachAvailableCount ?? 0;
    86→    final itemUsage = min(item?.aiCoachUsage ?? 0, itemMax);
    87→
    88→    return planUsage + itemUsage;
    89→  }
