    91→  /// ボール解析の上限数（Plan + Item の合算）
    92→  int get maxBalls {
    93→    final planMax =
    94→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.plan?.maxBalls ?? 0 : 0;
    95→    final itemMax = item?.ballAvailableCount ?? 0;
    96→    return planMax + itemMax;
    97→  }
    98→
    99→  /// AI コーチの上限数（Plan + Item の合算）
   100→  int get maxAICoachCount {
