   108→  /// プランの契約・有効期限状態
   109→  TeamPlanStatus get teamPlanStatus {
   110→    // 1. teamPlanがnull
   111→    if (teamPlan == null) {
   112→      if (nextTeamPlan != null) {
   113→        return TeamPlanStatus.nextPlanPending;
   114→      }
   115→      return TeamPlanStatus.noContract;
   116→    }
   117→
   118→    // 2. 期限切れか
   119→    final now = resolveTeamPlanNow();
   120→    final endDate = teamPlan!.endDate;
   121→    // 以下の場合は nextTeamPlan の endDate を使用する
   122→    // 1. nextTeamPlan が存在
   123→    // 2. teamPlan の endDate が nextTeamPlan の startDate と同じ (連続してプランを継続している)
   124→    final effectiveEndDate =
   125→        (nextTeamPlan != null && endDate == nextTeamPlan!.startDate)
   126→            ? nextTeamPlan!.endDate
   127→            : endDate;
   128→    final isExpired =
   129→        effectiveEndDate != null && effectiveEndDate.isBefore(now);
   130→    if (isExpired) {
   131→      if (nextTeamPlan != null) {
   132→        return TeamPlanStatus.nextPlanPending;
   133→      }
   134→      return TeamPlanStatus.expired;
   135→    }
   136→
   137→    // 3. 期限警告（30日以内）
   138→    if (effectiveEndDate != null) {
   139→      final oneMonthLater = now.add(const Duration(days: 30));
   140→      if (effectiveEndDate.isAfter(now) &&
   141→          effectiveEndDate.isBefore(oneMonthLater)) {
   142→        return TeamPlanStatus.expiringSoon;
   143→      }
   144→    }
   145→
   146→    // 4. 問題なし
   147→    return TeamPlanStatus.ok;
   148→  }
