          </Box>
        )}
      </TableCell>
      <TableCell align="left">
        <Box>
          <Typography variant="inherit">
            {translate('analyzed_balls')}
          </Typography>
          <Typography variant="inherit" sx={{ pl: 2 }}>
            Subscription: {team.teamPlan ? `${(team.ballUsage - (team.item?.ballUsage ?? 0)).toLocaleString()}/${team.planMaxBalls.toLocaleString()}` : '-'}
          </Typography>
          <Typography variant="inherit" sx={{ pl: 2 }}>
            Item: {team.item ? `${team.item.ballUsage.toLocaleString()}/${team.item.ballAvailableCount.toLocaleString()}` : '-'}
          </Typography>
          <Typography variant="inherit">
            {translate('ai_coach')}
          </Typography>
          <Typography variant="inherit" sx={{ pl: 2 }}>
            Subscription: {team.teamPlan ? `${(team.aiCoachUsage - (team.item?.aiCoachUsage ?? 0)).toLocaleString()}/${team.planMaxAiCoachs.toLocaleString()}` : '-'}
          </Typography>
          <Typography variant="inherit" sx={{ pl: 2 }}>
            Item: {team.item ? `${team.item.aiCoachUsage.toLocaleString()}/${team.item.aiCoachAvailableCount.toLocaleString()}` : '-'}
          </Typography>
        </Box>
        {team.nextTeamPlan && (
          <Box>
            <Typography variant="inherit" color="textDisabled">
              {translate('next_period')}
            </Typography>
            <Typography variant="inherit" color="textDisabled">
              {translate('analyzed_balls')}
              {' : '}
              {StringUtil.getNextTeamPlanBallAvailableString(team)}
            </Typography>
            <Typography variant="inherit" color="textDisabled">
              {translate('ai_coach')}
              {' : '}
              {StringUtil.getNextTeamPlanAiCoachAvailableString(team)}
