            {team.users.length <= 10
              ? _.chain(team.users)
                .sortBy(
                  (user) => user.createdAt?.getTime() ?? 0,
                )
                .map((user) => {
                  return (
                    <Box key={user.id}>
                      <Tooltip
                        title={
                          <>
                            {user.profile.username ||
                              '(no name)'}
                            <br />
                            {user.email}
                          </>
                        }
                        arrow
                        placement="left"
                      >
                        <Chip
                          color="default"
                          label={
                            user.profile.username || '(no name)'
                          }
                        />
                      </Tooltip>
                    </Box>
